import pytest
import redis.asyncio as redis
import json
import asyncio

REDIS_URL = "redis://localhost:6379"

# We use pytest.mark.asyncio to allow async/await inside the test
@pytest.mark.asyncio
async def test_worker_processing_question():
    """Tests if the worker picks up a job from Redis, hits vLLM, and returns an answer."""
    
    # 1. Connect to live Redis
    r = redis.from_url(REDIS_URL, decode_responses=True)

    await r.delete("questions")

    pubsub = r.pubsub()
    
    client_id = "test_worker_1"
    await pubsub.subscribe(f"alerts:{client_id}")
    await asyncio.sleep(0.1) # Give PubSub a millisecond to lock in
    
    # 2. Prepare the payload (Mimicking the FastAPI Gateway)
    # Using a valid 1x1 pixel base64 image so vLLM doesn't crash on garbage data
    dummy_b64 = ""
    
    payload = {
        "client_id": client_id,
        "data": {
            "type": "QUESTION",
            "text": "Is this a test?",
            "data": dummy_b64
        }
    }
    # 3. Push to the Redis "questions" queue
    print("\n[Test] Pushing job to Redis...")
    await r.lpush("questions", json.dumps(payload))
    
    # 4. Wait for the worker to process it and publish the answer back
    try:
        # We give it 15 seconds because vLLM might take a moment to generate text
        async with asyncio.timeout(15.0): 
            async for message in pubsub.listen():
                if message["type"] == "message":
                    response = json.loads(message["data"])
                    
                    assert response["type"] == "ANSWER"
                    print(f"\n[Test] Worker successfully replied: {response['message']}")
                    break # Exit the test successfully
                    
    except TimeoutError:
        pytest.fail("Worker did not respond within 15 seconds. Check the worker.py tmux pane for errors!")
    finally:
        await pubsub.unsubscribe()
        await r.aclose()